     /// Converts a number in the hundreds range (100-999) to Greek words.
     /// </summary>
     private string ConvertHundreds(long number, bool returnPluralized)
     {
         string result;

         if (number / 100 == 1)
         {
             if (number % 100 == 0)
             {
                 return HundredMap[number / 100];
             }

             result = HundredsMap[number / 100];
         }
         else
