             result = returnPluralized ? HundredsMap[number / 100] : HundredMap[number / 100];
         }

         if (number % 100 != 0)
         {
             // Anti-pattern: .ToLower() inside interpolation — compound allocation
             result += $" {ConvertImpl(number % 100, returnPluralized).ToLower()}";
         }

         return result;
     }

