     /// Converts a number in the thousands range (1,000-999,999) to Greek words.
     /// </summary>
     private string ConvertThousands(long number)
     {
         if (number / 1000 == 1)
         {
             if (number % 1000 == 0)
             {
                 return "χίλια";
